#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <sys/time.h>
#include <math.h>
#include <float.h>
#include <omp.h>

#ifdef TIMING
struct timeval tv;
struct timeval tv_total_start, tv_total_end;
struct timeval tv_h2d_start, tv_h2d_end;
struct timeval tv_d2h_start, tv_d2h_end;
struct timeval tv_kernel_start, tv_kernel_end;
struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
struct timeval tv_close_start, tv_close_end;
float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
      d2h_time = 0, close_time = 0, total_time = 0;

static void tvsub(struct timeval *t1, struct timeval *t0, struct timeval *td) {
  td->tv_sec = t1->tv_sec - t0->tv_sec;
  td->tv_usec = t1->tv_usec - t0->tv_usec;
  if (td->tv_usec < 0) {
    td->tv_sec--;
    td->tv_usec += 1000000;
  }
}
#endif

#define min(a, b) a > b ? b : a
#define ceilDiv(a, b) (a + b - 1) / b
#define print(x) printf(#x ": %lu\n", (unsigned long)x)
#define DEBUG 0

#define DEFAULT_THREADS_PER_BLOCK 256

#define MAX_ARGS 10
#define REC_LENGTH 53
#define LATITUDE_POS 28
#define OPEN 10000

typedef struct latLong {
  float lat;
  float lng;
} LatLong;

typedef struct record {
  char recString[REC_LENGTH];
  float distance;
} Record;

typedef struct {
  Record *data;
  int size;
  int capacity;
} RecordArray;

typedef struct {
  LatLong *data;
  int size;
  int capacity;
} LatLongArray;

static void initRecordArray(RecordArray *arr) {
  arr->data = NULL;
  arr->size = 0;
  arr->capacity = 0;
}

static void initLatLongArray(LatLongArray *arr) {
  arr->data = NULL;
  arr->size = 0;
  arr->capacity = 0;
}

static void pushRecord(RecordArray *arr, Record rec) {
  if (arr->size == arr->capacity) {
    int newCap = (arr->capacity == 0) ? 1024 : arr->capacity * 2;
    Record *tmp = (Record *)realloc(arr->data, (size_t)newCap * sizeof(Record));
    if (!tmp) {
      fprintf(stderr, "Out of memory\n");
      exit(1);
    }
    arr->data = tmp;
    arr->capacity = newCap;
  }
  arr->data[arr->size++] = rec;
}

static void pushLatLong(LatLongArray *arr, LatLong ll) {
  if (arr->size == arr->capacity) {
    int newCap = (arr->capacity == 0) ? 1024 : arr->capacity * 2;
    LatLong *tmp = (LatLong *)realloc(arr->data, (size_t)newCap * sizeof(LatLong));
    if (!tmp) {
      fprintf(stderr, "Out of memory\n");
      exit(1);
    }
    arr->data = tmp;
    arr->capacity = newCap;
  }
  arr->data[arr->size++] = ll;
}

static void freeRecordArray(RecordArray *arr) {
  free(arr->data);
  arr->data = NULL;
  arr->size = arr->capacity = 0;
}

static void freeLatLongArray(LatLongArray *arr) {
  free(arr->data);
  arr->data = NULL;
  arr->size = arr->capacity = 0;
}

int loadData(char *filename, RecordArray *records, LatLongArray *locations);
void findLowest(Record *records, float *distances, int numRecords, int topN);
void printUsage();
int parseCommandline(int argc, char *argv[], char *filename, int *r, float *lat, float *lng,
                     int *q, int *t, int *p, int *d);

static void euclid(const LatLong *locations, float *distances, int numRecords, float lat, float lng) {
  int globalId;
#pragma omp parallel for schedule(static)
  for (globalId = 0; globalId < numRecords; globalId++) {
    const LatLong *latLong = locations + globalId;
    float dlat = lat - latLong->lat;
    float dlng = lng - latLong->lng;
    distances[globalId] = sqrtf(dlat * dlat + dlng * dlng);
  }
}

int main(int argc, char *argv[]) {
  int i = 0;
  float lat = 0.0f, lng = 0.0f;
  int quiet = 0, timing = 0, platform = 0, device = 0;

  RecordArray records;
  LatLongArray locations;
  initRecordArray(&records);
  initLatLongArray(&locations);

  char filename[100];
  int resultsCount = 10;

  if (parseCommandline(argc, argv, filename, &resultsCount, &lat, &lng,
                       &quiet, &timing, &platform, &device)) {
    printUsage();
    freeRecordArray(&records);
    freeLatLongArray(&locations);
    return 0;
  }

  int numRecords = loadData(filename, &records, &locations);
  if (resultsCount > numRecords) resultsCount = numRecords;

  float *distances = (float *)malloc(sizeof(float) * (size_t)numRecords);
  if (!distances) {
    fprintf(stderr, "Out of memory\n");
    freeRecordArray(&records);
    freeLatLongArray(&locations);
    return 1;
  }

#ifdef TIMING
  gettimeofday(&tv_kernel_start, NULL);
#endif

  euclid(locations.data, distances, numRecords, lat, lng);

#ifdef TIMING
  gettimeofday(&tv_kernel_end, NULL);
  tvsub(&tv_kernel_end, &tv_kernel_start, &tv);
  kernel_time += tv.tv_sec * 1000.0f + (float)tv.tv_usec / 1000.0f;
#endif

  findLowest(records.data, distances, numRecords, resultsCount);

  if (!quiet)
    for (i = 0; resultsCount > i; i++) {
      printf("%s --> Distance=%f\n", records.data[i].recString, records.data[i].distance);
    }

  free(distances);
  freeRecordArray(&records);
  freeLatLongArray(&locations);

#ifdef TIMING
  printf("Exec: %f\n", kernel_time);
#endif

  return 0;
}

int loadData(char *filename, RecordArray *records, LatLongArray *locations) {
  FILE *flist, *fp;
  int i = 0;
  char dbname[64];
  int recNum = 0;

  flist = fopen(filename, "r");
  if (!flist) {
    fprintf(stderr, "error opening filelist\n");
    exit(1);
  }

  while (!feof(flist)) {
    if (fscanf(flist, "%s\n", dbname) != 1) {
      if (feof(flist)) break;
      fprintf(stderr, "error reading filelist\n");
      exit(0);
    }
    fp = fopen(dbname, "r");
    if (!fp) {
      printf("error opening a db\n");
      exit(1);
    }

    while (!feof(fp)) {
      Record record;
      LatLong latLong;

      if (fgets(record.recString, 49, fp) == NULL) break;
      fgetc(fp);
      if (feof(fp)) break;

      {
        char substr[6];

        for (i = 0; 5 > i; i++) substr[i] = *(record.recString + i + 28);
        substr[5] = '\0';
        latLong.lat = (float)atof(substr);

        for (i = 0; 5 > i; i++) substr[i] = *(record.recString + i + 33);
        substr[5] = '\0';
        latLong.lng = (float)atof(substr);
      }

      pushLatLong(locations, latLong);
      pushRecord(records, record);
      recNum++;
    }
    fclose(fp);
  }
  fclose(flist);

  return recNum;
}

void findLowest(Record *records, float *distances, int numRecords, int topN) {
  int i, j;
  float val;
  int minLoc;
  Record *tempRec;
  float tempDist;

  for (i = 0; topN > i; i++) {
    minLoc = i;
    for (j = i; j < numRecords; j++) {
      val = distances[j];
      if (distances[minLoc] > val) minLoc = j;
    }

    tempRec = &records[i];
    records[i] = records[minLoc];
    records[minLoc] = *tempRec;

    tempDist = distances[i];
    distances[i] = distances[minLoc];
    distances[minLoc] = tempDist;

    records[i].distance = distances[i];
  }
}

int parseCommandline(int argc, char *argv[], char *filename, int *r, float *lat, float *lng,
                     int *q, int *t, int *p, int *d) {
  int i;
  if (argc < 2) return 1;
  strncpy(filename, argv[1], 100);
  filename[99] = '\0';
  char flag;

  for (i = 1; i < argc; i++) {
    if ('-' == argv[i][0]) {
      flag = argv[i][1];
      switch (flag) {
        case 'r':
          i++;
          *r = atoi(argv[i]);
          break;
        case 'l':
          if ('a' == argv[i][2]) {
            *lat = (float)atof(argv[i + 1]);
          } else {
            *lng = (float)atof(argv[i + 1]);
          }
          i++;
          break;
        case 'h':
          return 1;
        case 'q':
          *q = 1;
          break;
        case 't':
          *t = 1;
          break;
        case 'p':
          i++;
          *p = atoi(argv[i]);
          break;
        case 'd':
          i++;
          *d = atoi(argv[i]);
          break;
      }
    }
  }
  if ((0 <= *d && *p < 0) || (0 <= *p && 0 > *d))
    return 1;
  return 0;
}

